#include <stdio.h>
#include <math.h>

int count_pairs(int n, int u, int v) {
    int count = 0;
    for (int w = 1; w <= n; w++) {
        for (int t = 1; t <= n; t++) {
            if (path_config(w, t) == path_config(u, v)) {
                count++;
            }
        }
    }
    return count;
}

int path_config(int w, int t) {
    int config = 0;
    while (w != t) {
        if (w > t) {
            config <<= 1;
            w >>= 1;
        } else {
            config = (config << 1) | 1;
            t = (t - 1) >> 1;
        }
    }
    return config;
}

int main() {
    int Q;
    scanf("%d", &Q);
    for (int i = 0; i < Q; i++) {
        int n, u, v;
        scanf("%d %d %d", &n, &u, &v);
        printf("%d\n", count_pairs(n, u, v));
    }
    return 0;
}

